const { Client } = require('@notionhq/client');
async function query({ database_id, filter, sorts }) {
  const notion = new Client({ auth: process.env.NOTION_TOKEN });
  const response = await notion.databases.query({ database_id, filter, sorts });
  return { results: response.results.map(p => ({ id: p.id, properties: p.properties })), has_more: response.has_more };
}
module.exports = { query };
